import{_ as t,c as a,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Plateformes IA: Consultation des quotas | opencode-mystatus","description":"Découvrez les fonctionnalités de consultation des quotas pour les 4 plateformes IA prises en charge: OpenAI, Zhipu AI, GitHub Copilot et Google Cloud.","frontmatter":{"title":"Plateformes IA: Consultation des quotas | opencode-mystatus","sidebarTitle":"Plateformes","subtitle":"Plateformes IA: Consultation des quotas","description":"Découvrez les fonctionnalités de consultation des quotas pour les 4 plateformes IA prises en charge: OpenAI, Zhipu AI, GitHub Copilot et Google Cloud.","order":2},"headers":[],"relativePath":"fr/vbgate/opencode-mystatus/platforms/index.md","filePath":"fr/vbgate/opencode-mystatus/platforms/index.md"}'),s={name:"fr/vbgate/opencode-mystatus/platforms/index.md"};function l(n,e,r,u,d,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="fonctionnalites-de-plateforme" tabindex="-1">Fonctionnalités de plateforme <a class="header-anchor" href="#fonctionnalites-de-plateforme" aria-label="Permalink to &quot;Fonctionnalités de plateforme&quot;">​</a></h1><p>Ce chapitre détaille en profondeur les fonctionnalités de consultation des quotas de chaque plateforme IA prise en charge par opencode-mystatus.</p><h2 id="plateformes-prises-en-charge" tabindex="-1">Plateformes prises en charge <a class="header-anchor" href="#plateformes-prises-en-charge" aria-label="Permalink to &quot;Plateformes prises en charge&quot;">​</a></h2><p>opencode-mystatus prend en charge les 4 plateformes IA principales suivantes :</p><table tabindex="0"><thead><tr><th>Plateforme</th><th>Type de limite</th><th>Caractéristiques</th></tr></thead><tbody><tr><td>OpenAI</td><td>Fenêtre glissante de 3h / 24h</td><td>Prend en charge les abonnements Plus, Team, Pro</td></tr><tr><td>Zhipu AI</td><td>Limite de token sur 5h / Quota mensuel MCP</td><td>Prend en charge le Coding Plan</td></tr><tr><td>GitHub Copilot</td><td>Quota mensuel</td><td>Affiche l&#39;utilisation des Premium Requests</td></tr><tr><td>Google Cloud</td><td>Calculé par modèle</td><td>Prend en charge les comptes multiples, 4 modèles</td></tr></tbody></table><h2 id="details-des-plateformes" tabindex="-1">Détails des plateformes <a class="header-anchor" href="#details-des-plateformes" aria-label="Permalink to &quot;Détails des plateformes&quot;">​</a></h2><h3 id="quota-openai" tabindex="-1"><a href="./openai-usage/">Quota OpenAI</a> <a class="header-anchor" href="#quota-openai" aria-label="Permalink to &quot;[Quota OpenAI](./openai-usage/)&quot;">​</a></h3><p>Approfondissez le mécanisme de consultation des quotas OpenAI :</p><ul><li>Différences entre les fenêtres glissantes de 3h et 24h</li><li>Mécanisme de partage de quota pour les comptes Team</li><li>Analyse du jeton JWT pour obtenir les informations du compte</li></ul><h3 id="quota-zhipu-ai" tabindex="-1"><a href="./zhipu-usage/">Quota Zhipu AI</a> <a class="header-anchor" href="#quota-zhipu-ai" aria-label="Permalink to &quot;[Quota Zhipu AI](./zhipu-usage/)&quot;">​</a></h3><p>Apprenez la consultation des quotas de Zhipu AI et Z.ai :</p><ul><li>Méthode de calcul de la limite de token sur 5h</li><li>Utilisation du quota mensuel MCP</li><li>Masquage de l&#39;affichage de la clé API</li></ul><h3 id="quota-github-copilot" tabindex="-1"><a href="./copilot-usage/">Quota GitHub Copilot</a> <a class="header-anchor" href="#quota-github-copilot" aria-label="Permalink to &quot;[Quota GitHub Copilot](./copilot-usage/)&quot;">​</a></h3><p>Maîtrisez la gestion des quotas GitHub Copilot :</p><ul><li>Signification des Premium Requests</li><li>Différences de quota selon le type d&#39;abonnement</li><li>Calcul du temps de réinitialisation mensuelle</li></ul><h3 id="quota-google-cloud" tabindex="-1"><a href="./google-usage/">Quota Google Cloud</a> <a class="header-anchor" href="#quota-google-cloud" aria-label="Permalink to &quot;[Quota Google Cloud](./google-usage/)&quot;">​</a></h3><p>Apprenez la consultation multi-comptes des quotas Google Cloud :</p><ul><li>Différences entre les 4 modèles (G3 Pro, G3 Image, G3 Flash, Claude)</li><li>Gestion et commutation multi-comptes</li><li>Mécanisme de lecture du fichier d&#39;authentification</li></ul><h2 id="guide-de-selection" tabindex="-1">Guide de sélection <a class="header-anchor" href="#guide-de-selection" aria-label="Permalink to &quot;Guide de sélection&quot;">​</a></h2><p>Choisissez le tutoriel correspondant selon la plateforme que vous utilisez :</p><ul><li><strong>OpenAI uniquement</strong> : Consultez directement <a href="./openai-usage/">Quota OpenAI</a></li><li><strong>Zhipu AI uniquement</strong> : Consultez directement <a href="./zhipu-usage/">Quota Zhipu AI</a></li><li><strong>Utilisateur multi-plateforme</strong> : Nous recommandons de lire tous les tutoriels de plateforme dans l&#39;ordre</li><li><strong>Utilisateur Google Cloud</strong> : Vous devez d&#39;abord installer le plugin <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a></li></ul><h2 id="etapes-suivantes" tabindex="-1">Étapes suivantes <a class="header-anchor" href="#etapes-suivantes" aria-label="Permalink to &quot;Étapes suivantes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, vous pouvez continuer avec <a href="./../advanced/">Fonctionnalités avancées</a> pour en savoir plus sur les options de configuration.</p>',23)])])}const m=t(s,[["render",l]]);export{h as __pageData,m as default};
